const alert = $input.item.json;
const body = alert.body || alert;
const alertData = body.alert || body;

const rule = alertData.rule || {};
const agent = alertData.agent || {};
const data = alertData.data || {};

const severityLevel = parseInt(rule.level) || 0;
let priority = 1;
if (severityLevel >= 12) priority = 3;
else if (severityLevel >= 7) priority = 2;

const prompt = 'You are a Tier 2 SOC Analyst. Summarize this security alert in a concise, professional briefing for an on-call engineer.\n\nAlert Details:\n- Rule: ' + (rule.description || 'N/A') + '\n- Rule ID: ' + (rule.id || 'N/A') + '\n- Severity: ' + severityLevel + '/15\n- Source IP: ' + (data.srcip || 'N/A') + '\n- Destination IP: ' + (data.dstip || 'N/A') + '\n- Affected Host: ' + (agent.name || 'N/A') + '\n- Timestamp: ' + (alertData.timestamp || 'N/A') + '\n- MITRE: ' + ((rule.mitre?.tactic || []).join(', ') || 'N/A') + '\n- Full Log: ' + (alertData.full_log || 'N/A') + '\n\nProvide JSON:\n{\n  "summary": "2-3 sentences",\n  "iocs": ["array"],\n  "immediate_actions": ["actions"],\n  "severity_assessment": "text"}\n\nFormat: Professional, clinical tone. No speculation. JSON only.';

return {
  json: {
    alertData: {
      rule_id: rule.id,
      rule_description: rule.description,
      severity: severityLevel,
      priority: priority,
      source_ip: data.srcip || 'N/A',
      dest_ip: data.dstip || 'N/A',
      hostname: agent.name || 'N/A',
      agent_id: agent.id || 'N/A',
      full_log: alertData.full_log || '',
      timestamp: alertData.timestamp || new Date().toISOString(),
      mitre_tactics: (rule.mitre?.tactic || []).join(', '),
      mitre_ids: (rule.mitre?.id || []).join(', '),
      groups: (rule.groups || []).join(', ')
    },
    prompt: prompt
  }
};

const data = $input.item.json;
let summary = { summary: 'No AI response', iocs: [], immediate_actions: [], severity_assessment: 'Unknown' };

try {
  if (data.choices && data.choices[0]?.message?.content) {
    const text = data.choices[0].message.content;
    const match = text.match(/\{[\s\S]*\}/);
    if (match) summary = JSON.parse(match[0]);
  }
} catch (e) {
  summary.summary = 'Error parsing AI response: ' + e.message;
}

return { json: summary };
